// templates/mod.rs
//
// All HTML is generated by Rust functions returning String.
// No template engine dependency — zero overhead, zero mismatches.
//
// Security: EVERY user-supplied string is passed through escape_html()
// before insertion. Template strings are trusted Rust literals only.
//
// Design: Minimalist 4chan-inspired. Works on mobile. Dark mode via
// CSS media query. Fast load (single CSS file, no JS frameworks).

use crate::models::*;
use crate::utils::{files::format_file_size, sanitize::escape_html};
use chrono::{DateTime, TimeZone, Utc};

// ─── Base layout ─────────────────────────────────────────────────────────────

fn format_timestamp(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%Y-%m-%d %H:%M:%S UTC").to_string(),
        _ => "unknown".to_string(),
    }
}

fn format_timestamp_short(ts: i64) -> String {
    match Utc.timestamp_opt(ts, 0) {
        chrono::LocalResult::Single(dt) => dt.format("%m/%d/%y(%a)%H:%M:%S").to_string(),
        _ => "?".to_string(),
    }
}

/// Wrap a page body in the full HTML shell with nav bar.
fn base_layout(title: &str, board_short: Option<&str>, body: &str, csrf_token: &str, boards: &[Board]) -> String {
    let board_links: String = boards
        .iter()
        .map(|b| {
            format!(
                r#"[<a href="/{}/">{}</a>]"#,
                escape_html(&b.short_name),
                escape_html(&b.short_name)
            )
        })
        .collect::<Vec<_>>()
        .join(" ");

    let search_bar = if let Some(b) = board_short {
        format!(
            r#"<form class="search-form" method="GET" action="/{}/search">
                <input type="text" name="q" placeholder="Search /{}/…" maxlength="64">
                <button type="submit">Search</button>
            </form>"#,
            escape_html(b), escape_html(b)
        )
    } else {
        String::new()
    };

    format!(
        r#"<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<meta name="referrer" content="no-referrer">
<title>{title}</title>
<link rel="stylesheet" href="/static/style.css">
</head>
<body>
<header class="site-header">
  <nav class="board-list">
    {board_links}
    [<a href="/admin">Admin</a>]
  </nav>
  <div class="header-search">{search_bar}</div>
</header>
<main>
{body}
</main>
<footer class="site-footer">
  <p>This is a private imageboard. <a href="/">Home</a></p>
</footer>
<!-- CSRF token embedded for JS-less forms -->
<input type="hidden" id="csrf_global" value="{csrf_token}">
</body>
</html>"#,
        title = escape_html(title),
        board_links = board_links,
        search_bar = search_bar,
        body = body,
        csrf_token = escape_html(csrf_token),
    )
}

// ─── Index (board list) ───────────────────────────────────────────────────────

pub fn index_page(boards: &[Board], csrf_token: &str) -> String {
    let sfw_boards: Vec<&Board> = boards.iter().filter(|b| !b.nsfw).collect();
    let nsfw_boards: Vec<&Board> = boards.iter().filter(|b| b.nsfw).collect();

    fn board_cards(list: &[&Board]) -> String {
        list.iter().map(|b| {
            let nsfw_badge = if b.nsfw { r#"<span class="nsfw-badge">NSFW</span>"# } else { "" };
            format!(
                r#"<a class="board-card" href="/{short}/">
  <div class="board-card-short">/{short}/</div>
  <div class="board-card-name">{name}{nsfw}</div>
  <div class="board-card-desc">{desc}</div>
</a>"#,
                short = escape_html(&b.short_name),
                name  = escape_html(&b.name),
                nsfw  = nsfw_badge,
                desc  = escape_html(&b.description),
            )
        }).collect()
    }

    let sfw_section = if !sfw_boards.is_empty() {
        format!(
            "<div class=\"index-section\">\n  <h2 class=\"index-section-title\">Boards</h2>\n  <div class=\"board-cards\">{}</div>\n</div>",
            board_cards(&sfw_boards)
        )
    } else { String::new() };

    let nsfw_section = if !nsfw_boards.is_empty() {
        format!(
            "<div class=\"index-section\">\n  <h2 class=\"index-section-title\">Adult Boards <span class=\"nsfw-badge\">NSFW</span></h2>\n  <div class=\"board-cards\">{}</div>\n</div>",
            board_cards(&nsfw_boards)
        )
    } else { String::new() };

    let empty_msg = if boards.is_empty() {
        "<p class=\"index-empty\">No boards yet. An admin must create boards first.</p>".to_string()
    } else { String::new() };

    let body = format!(
        "<div class=\"index-hero\">\n  <h1 class=\"index-title\">Welcome</h1>\n  <p class=\"index-subtitle\">Select a board below to start browsing.</p>\n</div>\n{sfw}{nsfw}{empty}",
        sfw   = sfw_section,
        nsfw  = nsfw_section,
        empty = empty_msg,
    );

    base_layout("Imageboard — Home", None, &body, csrf_token, boards)
}

// ─── Board index (thread list) ────────────────────────────────────────────────

pub fn board_page(
    board: &Board,
    summaries: &[ThreadSummary],
    pagination: &Pagination,
    csrf_token: &str,
    boards: &[Board],
) -> String {
    let mut body = String::new();

    // New thread form
    body.push_str(&new_thread_form(&board.short_name, csrf_token));

    body.push_str(&format!(
        r#"<div class="board-header"><h1>/{}/  — {}</h1><p class="board-desc">{}</p></div>"#,
        escape_html(&board.short_name),
        escape_html(&board.name),
        escape_html(&board.description),
    ));

    // Thread summaries
    for summary in summaries {
        body.push_str(&render_thread_summary(summary, &board.short_name, csrf_token));
    }

    // Pagination
    body.push_str(&render_pagination(pagination, &format!("/{}/", board.short_name)));

    base_layout(
        &format!("/{}/", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
    )
}

fn new_thread_form(board_short: &str, csrf_token: &str) -> String {
    format!(
        r#"<div class="post-form-container">
<details open>
<summary>New Thread</summary>
<form class="post-form" method="POST" action="/{board}/" enctype="multipart/form-data">
  <input type="hidden" name="_csrf" value="{csrf}">
  <table>
    <tr><td><label>Name</label></td>
        <td><input type="text" name="name" placeholder="Anonymous" maxlength="64"></td></tr>
    <tr><td><label>Subject</label></td>
        <td><input type="text" name="subject" maxlength="128"> 
            <button type="submit">New Thread</button></td></tr>
    <tr><td><label>Body</label></td>
        <td><textarea name="body" rows="5" maxlength="4096" required></textarea></td></tr>
    <tr><td><label>File</label></td>
        <td><input type="file" name="file" accept="image/jpeg,image/png,image/gif,image/webp,video/mp4,video/webm"></td></tr>
    <tr><td><label>Deletion token</label></td>
        <td><input type="text" name="deletion_token" placeholder="Password to delete post" maxlength="64"></td></tr>
  </table>
</form>
</details>
</div>"#,
        board = escape_html(board_short),
        csrf = escape_html(csrf_token),
    )
}

fn render_thread_summary(summary: &ThreadSummary, board_short: &str, csrf_token: &str) -> String {
    let t = &summary.thread;
    let mut html = String::new();

    let sticky_label = if t.sticky { "<span class=\"tag sticky\">STICKY</span> " } else { "" };
    let locked_label = if t.locked { "<span class=\"tag locked\">LOCKED</span> " } else { "" };

    // OP post
    html.push_str(&format!(
        r#"<div class="thread" id="t{}">
<div class="op post" id="p{}">"#,
        t.id, t.op_id.unwrap_or(0)
    ));

    // OP image
    if let (Some(file), Some(thumb)) = (&t.op_file, &t.op_thumb) {
        html.push_str(&format!(
            r#"<div class="file-container">
<a href="/uploads/{}" target="_blank">
<img class="thumb" src="/uploads/{}" loading="lazy" alt="image">
</a></div>"#,
            escape_html(file),
            escape_html(thumb)
        ));
    }

    html.push_str(&format!(
        r#"<div class="post-meta">
{sticky}{locked}
<strong class="name">{name}</strong>
<span class="post-time">{time}</span>
<a class="post-num" href="/{board}/thread/{tid}">No.{op_id}</a>
</div>"#,
        sticky = sticky_label,
        locked = locked_label,
        name = escape_html(t.op_name.as_deref().unwrap_or("Anonymous")),
        time = format_timestamp_short(t.created_at),
        board = escape_html(board_short),
        tid = t.id,
        op_id = t.op_id.unwrap_or(0),
    ));

    if let Some(subject) = &t.subject {
        html.push_str(&format!(
            r#"<div class="subject"><a href="/{}/thread/{}"><strong>{}</strong></a></div>"#,
            escape_html(board_short),
            t.id,
            escape_html(subject)
        ));
    }

    if let Some(body) = &t.op_body {
        // body_html is pre-rendered, but for summary we truncate the raw body
        let truncated = if body.len() > 300 {
            format!(
                "{} <a href=\"/{}/thread/{}\">…[Read more]</a>",
                escape_html(&body[..300]),
                escape_html(board_short),
                t.id
            )
        } else {
            escape_html(body)
        };
        html.push_str(&format!("<div class=\"post-body\">{}</div>", truncated));
    }

    html.push_str(&format!(
        r#"<div class="thread-footer">
<a href="/{board}/thread/{tid}">[Reply] ({n} {word})</a>
</div>
</div>"#,
        board = escape_html(board_short),
        tid = t.id,
        n = t.reply_count,
        word = if t.reply_count == 1 { "reply" } else { "replies" },
    ));

    // Omitted posts notice
    if summary.omitted > 0 {
        html.push_str(&format!(
            r#"<div class="omitted">{} posts omitted. <a href="/{}/thread/{}">View thread</a></div>"#,
            summary.omitted,
            escape_html(board_short),
            t.id
        ));
    }

    // Preview replies
    for post in &summary.preview_posts {
        html.push_str(&render_post(post, board_short, csrf_token, false));
    }

    html.push_str("</div><hr class=\"thread-sep\">");
    html
}

// ─── Thread page ──────────────────────────────────────────────────────────────

pub fn thread_page(
    board: &Board,
    thread: &Thread,
    posts: &[Post],
    csrf_token: &str,
    boards: &[Board],
) -> String {
    let mut body = String::new();

    let locked_notice = if thread.locked {
        r#"<div class="notice locked-notice">This thread is locked. No new replies allowed.</div>"#
    } else {
        ""
    };

    body.push_str(&format!(
        r#"<div class="board-header">
<a href="/{short}/">Return</a> | <a href="/{short}/catalog">Catalog</a>
</div>
{locked}"#,
        short = escape_html(&board.short_name),
        locked = locked_notice,
    ));

    // All posts
    for post in posts {
        body.push_str(&render_post(post, &board.short_name, csrf_token, true));
    }

    // Reply form (if not locked)
    if !thread.locked {
        body.push_str(&reply_form(&board.short_name, thread.id, csrf_token));
    }

    base_layout(
        &format!(
            "/{}/  {}",
            board.short_name,
            thread.subject.as_deref().unwrap_or("Thread")
        ),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
    )
}

pub fn render_post(post: &Post, board_short: &str, csrf_token: &str, show_delete: bool) -> String {
    let tripcode_html = post
        .tripcode
        .as_ref()
        .map(|t| format!("<span class=\"tripcode\">{}</span>", escape_html(t)))
        .unwrap_or_default();

    let op_class = if post.is_op { " op" } else { " reply" };

    let mut html = format!(
        r##"<div class="post{op_class}" id="p{id}">
<div class="post-meta">
<strong class="name">{name}</strong>{tripcode}
<span class="post-time">{time}</span>
<a class="post-num" href="#{id_link}"
   onclick="appendReply({id})">No.{id}</a>
</div>"##,
        op_class = op_class,
        id = post.id,
        name = escape_html(&post.name),
        tripcode = tripcode_html,
        time = format_timestamp_short(post.created_at),
        id_link = post.id,
    );

    // Subject
    if let Some(subject) = &post.subject {
        html.push_str(&format!(
            "<div class=\"subject\"><strong>{}</strong></div>",
            escape_html(subject)
        ));
    }

    // Image / Video
    if let (Some(file), Some(thumb)) = (&post.file_path, &post.thumb_path) {
        let size_str = post.file_size.map(format_file_size).unwrap_or_default();
        let name_str = post.file_name.as_deref().unwrap_or("file");
        let is_video = post.mime_type.as_deref().map(|m| m.starts_with("video/")).unwrap_or(false);
        let mime = post.mime_type.as_deref().unwrap_or("video/mp4");

        if is_video {
            html.push_str(&format!(
                r#"<div class="file-container">
<div class="file-info"><a href="/uploads/{file}">{orig_name}</a> ({size})</div>
<video class="media-thumb video-player" src="/uploads/{file}" controls preload="metadata"
       poster="/uploads/{thumb}" type="{mime}"></video>
</div>"#,
                file = escape_html(file),
                thumb = escape_html(thumb),
                orig_name = escape_html(name_str),
                size = escape_html(&size_str),
                mime = escape_html(mime),
            ));
        } else {
            html.push_str(&format!(
                r#"<div class="file-container">
<div class="file-info"><a href="/uploads/{file}">{orig_name}</a> ({size})</div>
<a href="/uploads/{file}" target="_blank">
<img class="thumb" src="/uploads/{thumb}" loading="lazy" alt="image"
     onclick="expandImage(this, '/uploads/{file}')">
</a>
</div>"#,
                file = escape_html(file),
                thumb = escape_html(thumb),
                orig_name = escape_html(name_str),
                size = escape_html(&size_str),
            ));
        }
    }

    // Post body (pre-rendered HTML — already sanitised)
    html.push_str(&format!(
        r#"<div class="post-body">{}</div>"#,
        post.body_html // This is pre-rendered, sanitised HTML from our renderer
    ));

    // Delete form
    if show_delete {
        html.push_str(&format!(
            r#"<div class="post-controls">
<form class="delete-form" method="POST" action="/delete">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="post_id" value="{post_id}">
<input type="hidden" name="board" value="{board}">
<input type="text" name="deletion_token" placeholder="Deletion token" maxlength="64" size="16">
<button type="submit" class="del-btn">Delete</button>
</form>
</div>"#,
            csrf = escape_html(csrf_token),
            post_id = post.id,
            board = escape_html(board_short),
        ));
    }

    html.push_str("</div>\n");
    html
}

fn reply_form(board_short: &str, thread_id: i64, csrf_token: &str) -> String {
    format!(
        r#"<div class="post-form-container reply-form-container">
<details open>
<summary>Reply to Thread</summary>
<form class="post-form" method="POST" action="/{board}/thread/{tid}"
      enctype="multipart/form-data">
  <input type="hidden" name="_csrf" value="{csrf}">
  <table>
    <tr><td><label>Name</label></td>
        <td><input type="text" name="name" placeholder="Anonymous" maxlength="64"></td></tr>
    <tr><td><label>Body</label></td>
        <td><textarea id="reply-body" name="body" rows="4" maxlength="4096" required></textarea>
            <button type="submit">Post Reply</button></td></tr>
    <tr><td><label>File</label></td>
        <td><input type="file" name="file" accept="image/jpeg,image/png,image/gif,image/webp,video/mp4,video/webm"></td></tr>
    <tr><td><label>Deletion token</label></td>
        <td><input type="text" name="deletion_token" placeholder="Password to delete" maxlength="64"></td></tr>
  </table>
</form>
</details>
</div>
<script>
// Append >>PostID to reply textarea when clicking post number
function appendReply(id) {{
  var ta = document.getElementById('reply-body');
  if (ta) {{
    ta.value += '>>' + id + '\n';
    ta.focus();
  }}
  return false;
}}
// Inline image expand/collapse on click
function expandImage(img, full) {{
  if (img.dataset.expanded === 'true') {{
    img.src = img.dataset.thumb;
    img.dataset.expanded = 'false';
    img.style.maxWidth = '';
  }} else {{
    img.dataset.thumb = img.src;
    img.src = full;
    img.dataset.expanded = 'true';
    img.style.maxWidth = '100%';
  }}
  return false;
}}
</script>"#,
        board = escape_html(board_short),
        tid = thread_id,
        csrf = escape_html(csrf_token),
    )
}

// ─── Catalog page ─────────────────────────────────────────────────────────────

pub fn catalog_page(
    board: &Board,
    threads: &[Thread],
    csrf_token: &str,
    boards: &[Board],
) -> String {
    let bs = escape_html(&board.short_name);
    let bn = escape_html(&board.name);
    let mut body = {
        let mut s = String::new();
        s.push_str(&format!(r#"<div class="board-header"><h1>/{bs}/  — {bn} — Catalog</h1><a href="/{bs}/">Return to index</a></div><div class="catalog-grid">"#, bs=bs, bn=bn));
        s
    };

    for t in threads {
        let thumb_html = if let Some(thumb) = &t.op_thumb {
            format!(
                r#"<img class="catalog-thumb" src="/uploads/{}" loading="lazy" alt="">"#,
                escape_html(thumb)
            )
        } else {
            r#"<div class="catalog-no-image">No image</div>"#.to_string()
        };

        let subject = t
            .subject
            .as_deref()
            .unwrap_or_else(|| t.op_body.as_deref().unwrap_or(""));
        let preview: String = subject.chars().take(80).collect();

        body.push_str(&format!(
            r#"<div class="catalog-item{sticky}">
<a href="/{board}/thread/{tid}">
{thumb}
<div class="catalog-info">
<span class="catalog-replies">{replies}R</span>
<p class="catalog-subject">{subject}</p>
</div>
</a>
</div>"#,
            sticky = if t.sticky { " sticky" } else { "" },
            board = escape_html(&board.short_name),
            tid = t.id,
            thumb = thumb_html,
            replies = t.reply_count,
            subject = escape_html(&preview),
        ));
    }

    body.push_str("</div>");
    base_layout(
        &format!("/{}/  Catalog", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
    )
}

// ─── Search results ───────────────────────────────────────────────────────────

pub fn search_page(
    board: &Board,
    query: &str,
    posts: &[Post],
    pagination: &Pagination,
    csrf_token: &str,
    boards: &[Board],
) -> String {
    let mut body = format!(
        r#"<div class="page-box">
<h2>Search results for "{}" in /{}/</h2>
<form method="GET" action="/{}/search">
  <input type="text" name="q" value="{}" maxlength="64">
  <button type="submit">Search</button>
</form>"#,
        escape_html(query),
        escape_html(&board.short_name),
        escape_html(&board.short_name),
        escape_html(query),
    );

    if posts.is_empty() {
        body.push_str("<p>No results found.</p>");
    } else {
        body.push_str(&format!("<p>{} result(s) found</p>", pagination.total));
        for post in posts {
            body.push_str(&render_post(post, &board.short_name, csrf_token, false));
        }
        body.push_str(&render_pagination(
            pagination,
            &format!("/{}/search?q={}", board.short_name, urlencoding_simple(query)),
        ));
    }

    body.push_str("</div>");
    base_layout(
        &format!("Search — /{}/", board.short_name),
        Some(&board.short_name),
        &body,
        csrf_token,
        boards,
    )
}

// ─── Admin pages ──────────────────────────────────────────────────────────────

pub fn admin_login_page(error: Option<&str>, csrf_token: &str, boards: &[Board]) -> String {
    let err_html = error
        .map(|e| format!("<div class=\"error\">{}</div>", escape_html(e)))
        .unwrap_or_default();

    let body = format!(
        r#"<div class="page-box admin-login">
<h2>Admin Login</h2>
{err}
<form method="POST" action="/admin/login">
<input type="hidden" name="_csrf" value="{csrf}">
<table>
<tr><td>Username</td><td><input type="text" name="username" autofocus required></td></tr>
<tr><td>Password</td><td><input type="password" name="password" required></td></tr>
<tr><td></td><td><button type="submit">Login</button></td></tr>
</table>
</form>
</div>"#,
        err = err_html,
        csrf = escape_html(csrf_token),
    );
    base_layout("Admin Login", None, &body, csrf_token, boards)
}

pub fn admin_panel_page(
    boards: &[Board],
    bans: &[Ban],
    filters: &[WordFilter],
    csrf_token: &str,
) -> String {
    // Board management section
    let mut board_rows = String::new();
    for b in boards {
        board_rows.push_str(&format!(
            r#"<tr>
<td>/{}/</td><td>{}</td><td>{}</td>
<td>
<form method="POST" action="/admin/board/delete" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="board_id" value="{id}">
<button type="submit" onclick="return confirm('Delete /{short}/ and all its content?')">Delete</button>
</form>
</td>
</tr>"#,
            escape_html(&b.short_name),
            escape_html(&b.name),
            escape_html(&b.description),
            csrf = escape_html(csrf_token),
            id = b.id,
            short = escape_html(&b.short_name),
        ));
    }

    // Bans section
    let mut ban_rows = String::new();
    for ban in bans {
        let expires = ban
            .expires_at
            .map(format_timestamp)
            .unwrap_or_else(|| "Permanent".to_string());
        ban_rows.push_str(&format!(
            r#"<tr>
<td class="ip-hash">{}</td>
<td>{}</td>
<td>{}</td>
<td>
<form method="POST" action="/admin/ban/remove" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="ban_id" value="{id}">
<button type="submit">Lift</button>
</form>
</td>
</tr>"#,
            escape_html(&ban.ip_hash[..16]),  // show partial hash only
            escape_html(ban.reason.as_deref().unwrap_or("")),
            escape_html(&expires),
            csrf = escape_html(csrf_token),
            id = ban.id,
        ));
    }

    // Word filters section
    let mut filter_rows = String::new();
    for f in filters {
        filter_rows.push_str(&format!(
            r#"<tr>
<td>{}</td><td>{}</td>
<td>
<form method="POST" action="/admin/filter/remove" style="display:inline">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="hidden" name="filter_id" value="{id}">
<button type="submit">Remove</button>
</form>
</td>
</tr>"#,
            escape_html(&f.pattern),
            escape_html(&f.replacement),
            csrf = escape_html(csrf_token),
            id = f.id,
        ));
    }

    let body = format!(
        r#"<div class="admin-panel">
<h1>Admin Panel</h1>
<form method="POST" action="/admin/logout">
<input type="hidden" name="_csrf" value="{csrf}">
<button type="submit">Logout</button>
</form>

<section class="admin-section">
<h2>Boards</h2>
<table class="admin-table">
<thead><tr><th>Board</th><th>Name</th><th>Description</th><th>Action</th></tr></thead>
<tbody>{board_rows}</tbody>
</table>
<h3>Create Board</h3>
<form method="POST" action="/admin/board/create">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="text" name="short_name" placeholder="short (e.g. tech)" maxlength="8" required>
<input type="text" name="name" placeholder="Full Name" maxlength="64" required>
<input type="text" name="description" placeholder="Description" maxlength="256">
<label><input type="checkbox" name="nsfw" value="1"> NSFW</label>
<button type="submit">Create</button>
</form>
</section>

<section class="admin-section">
<h2>Active Bans</h2>
<table class="admin-table">
<thead><tr><th>IP Hash (partial)</th><th>Reason</th><th>Expires</th><th>Action</th></tr></thead>
<tbody>{ban_rows}</tbody>
</table>
</section>

<section class="admin-section">
<h2>Word Filters</h2>
<table class="admin-table">
<thead><tr><th>Pattern</th><th>Replacement</th><th>Action</th></tr></thead>
<tbody>{filter_rows}</tbody>
</table>
<h3>Add Filter</h3>
<form method="POST" action="/admin/filter/add">
<input type="hidden" name="_csrf" value="{csrf}">
<input type="text" name="pattern" placeholder="Pattern to match" required>
<input type="text" name="replacement" placeholder="Replace with">
<button type="submit">Add</button>
</form>
</section>
</div>"#,
        csrf = escape_html(csrf_token),
        board_rows = board_rows,
        ban_rows = ban_rows,
        filter_rows = filter_rows,
    );

    base_layout("Admin Panel", None, &body, csrf_token, boards)
}

// ─── Error page ───────────────────────────────────────────────────────────────

pub fn error_page(code: u16, message: &str) -> String {
    format!(
        r#"<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Error {code}</title>
<link rel="stylesheet" href="/static/style.css">
</head>
<body>
<div class="page-box error-page">
<h1>Error {code}</h1>
<p>{message}</p>
<p><a href="/">Return to home</a></p>
</div>
</body>
</html>"#,
        code = code,
        message = escape_html(message),
    )
}

// ─── Pagination helper ────────────────────────────────────────────────────────

fn render_pagination(p: &Pagination, base_url: &str) -> String {
    if p.total_pages() <= 1 {
        return String::new();
    }

    let separator = if base_url.contains('?') { "&" } else { "?" };

    let mut html = String::from(r#"<div class="pagination">"#);

    if p.has_prev() {
        html.push_str(&format!(
            r#"<a href="{}{}page={}">[Prev]</a> "#,
            base_url,
            separator,
            p.page - 1
        ));
    }

    html.push_str(&format!("Page {} of {}", p.page, p.total_pages()));

    if p.has_next() {
        html.push_str(&format!(
            r#" <a href="{}{}page={}">[Next]</a>"#,
            base_url,
            separator,
            p.page + 1
        ));
    }

    html.push_str("</div>");
    html
}

/// Minimal URL encoding for query strings (only percent-encodes unsafe chars)
fn urlencoding_simple(s: &str) -> String {
    s.chars()
        .map(|c| match c {
            'A'..='Z' | 'a'..='z' | '0'..='9' | '-' | '_' | '.' | '~' => c.to_string(),
            ' ' => "+".to_string(),
            _ => format!("%{:02X}", c as u32),
        })
        .collect()
}
